def xtrackers_lookup_isin(isin):
    """Return Xtrackers ETF info dict by ISIN, or None."""
    return XTRACKERS_LOOKUP.get(isin.strip().upper())

def xtrackers_lookup_name(name_fragment):
    """Find Xtrackers ETFs by partial name match. Returns list."""
    name_fragment = name_fragment.lower()
    return [v for v in XTRACKERS_LOOKUP.values()
            if name_fragment in v["name"].lower()]

